local a={}a.__index=a a.Folder='Luna_Hub'a.Ignore={}a.Options={}a.Luna=nil function a.Init(b,c)b.Luna=c end function a.BuildFolder(b)pcall(function()if not isfolder(b.Folder)then makefolder(b.Folder)end if not isfolder(b.Folder..'/Configs')then makefolder(b.Folder..'/Configs')end end)end function a.Save(b,c)if not c then return false,'No config name provided'end if not b.Luna then return false,'Luna not initialized'end b.Options=b.Luna.Options or{}b:BuildFolder()local d={options={},savedAt=os.date'%Y-%m-%d %H:%M:%S'}for e,f in pairs(b.Options)do if type(f)=='table'and not b.Ignore[e]then local g pcall(function()if f.Type=='Colorpicker'then local h=f:GetValue()g={Color={R=h.Color.R,G=h.Color.G,B=h.Color.B},Transparency=h.Transparency or 0}elseif f.Type=='Dropdown'then g=f:GetValue()elseif f.Value~=nil then g=f.Value elseif f.GetValue then g=f:GetValue()end end)if g~=nil then table.insert(d.options,{type=f.Type or'Unknown',name=e,value=g,multi=f.Multi or false})end end end local e,f=b.Folder..'/Configs/'..c..'.json',game:GetService'HttpService':JSONEncode(d)writefile(e,f)return true end function a.Load(b,c)if not c then return false,'No config name provided'end if not b.Luna then return false,'Luna not initialized'end b.Options=b.Luna.Options or{}local d=b.Folder..'/Configs/'..c..'.json'if not isfile(d)then return false,'Config not found'end local e=game:GetService'HttpService':JSONDecode(readfile(d))for f,g in ipairs(e.options)do local h=b.Options[g.name]if h then pcall(function()local i=g.value if g.type=='Colorpicker'then h:SetValue({Color=Color3.new(i.Color.R,i.Color.G,i.Color.B),Transparency=i.Transparency},false)elseif g.type=='Dropdown'then if h.Multi then h:Set_Value(i,false)else h:Set_Value(nil,false)h:Set_Value(i,false)end elseif h.Set_Value then h:Set_Value(i,false)end end)end end return true end function a.Delete(b,c)local d=b.Folder..'/Configs/'..c..'.json'if isfile(d)then delfile(d)return true end return false end function a.ListConfigs(b)local c,d={},b.Folder..'/Configs/'if not isfolder(d)then return c end for e,f in ipairs(listfiles(d))do if f:sub(-5)=='.json'then table.insert(c,f:match'([^/\\]+)%.json$')end end return c end function a.CreateUI(b,c)c:Create_Section{Title='Config Manager'}local d,e=nil,(c:Create_Input('config_name',{Title='Config Name',Placeholder='Enter name...'}))c:Create_Button{Title='Save Config',Callback=function()local f=(b.Luna.Options.config_name and b.Luna.Options.config_name.Value)or''if f==''then b.Luna:Notify{Title='Error',Content='Enter config name'}return end b:Save(f)if d then d:Set_Value(b:ListConfigs())end end}d=c:Create_Dropdown('config_list',{Title='Configs',Options=b:ListConfigs()})c:Create_Button{Title='Load Config',Callback=function()local f=b.Luna.Options.config_list and b.Luna.Options.config_list.Value if not f then return end b:Load(f)end}c:Create_Button{Title='Delete Config',Callback=function()local f=b.Luna.Options.config_list and b.Luna.Options.config_list.Value if not f then return end b:Delete(f)if d then d:Set_Value(b:ListConfigs())end end}c:Create_Button{Title='Refresh',Callback=function()if d then d:Set_Value(b:ListConfigs())end end}end return a
